args.sparql:
SELECT ?county WHERE {
  ?station wdt:P31 wd:Q19822986 ;
          wdt:P1846 "Northern Michigan's #1 Hit Music Channel" ;
          wdt:P131 ?city .
  ?city wdt:P131 ?county .
}

SELECT ?county WHERE {
  ?city wdt:P36 ?county;
         wdt:P131 wd:Q32.
  ?station wdt:P31 wd:Q19822986;
           wdt:P131 ?city.
  ?station rdfs:label ?label.
  FILTER(LANG(?label) = 'en').
  FILTER(CONTAINS(LCASE(?label), 'hit')) .
  FILTER(CONTAINS(LCASE(?label), 'music')) .
  FILTER(CONTAINS(LCASE(?label), 'northern'))
}
